using Financeiro.Domain.Entities; using Financeiro.Domain.Interfaces.Repositories; using Financeiro.Infrastructure.Persistence; using Microsoft.EntityFrameworkCore;
namespace Financeiro.Infrastructure.Repositories; public class UsuarioRepository : IUsuarioRepository{ private readonly AppDbContext _ctx; public UsuarioRepository(AppDbContext ctx){_ctx=ctx;} public Task<Usuario?> GetByEmailAsync(string email,CancellationToken cancellationToken=default)=>_ctx.Usuarios.AsNoTracking().FirstOrDefaultAsync(x=>x.Email==email,cancellationToken); }
